use std::collections::VecDeque;
use std::time::{Duration, Instant};

struct RetryTracker {
    history: VecDeque<Instant>,
    max_history_size: usize,
}

impl RetryTracker {
    fn new(max_size: usize) -> Self {
        RetryTracker {
            history: VecDeque::with_capacity(max_size),
            max_history_size: max_size,
        }
    }

    fn record_failure(&mut self) {
        let now = Instant::now();
        self.history.push_back(now);
        if self.history.len() > self.max_history_size {
            self.history.pop_front();
        }
    }

    fn calculate_wait_time(&self) -> Option<Duration> {
        if self.history.is_empty() {
            return None;
        }

        let oldest_failure = *self.history.front().unwrap();
        let time_since_oldest = Duration::from_millis(Instant::now().duration_since(oldest_failure).as_millis() as u64);

        if self.history.len() == 1 {
            return Some(Duration::from_millis(500));
        }

        let base_delay = Duration::from_millis((self.history.len() as u64).pow(1) * 100);
        Some(time_since_oldest.max(base_delay)) 
    }

    fn is_ready_to_retry(&self, required_wait: Duration) -> bool {
        let calculated_wait = self.calculate_wait_time();
        match calculated_wait {
            Some(wait) => wait >= required_wait,
            None => false,
        }
    }
}

fn main() {
    let mut tracker = RetryTracker::new(5);
    println!("Initial state check...");
    if let Some(wait) = tracker.calculate_wait_time() { 
        println!("Wait time: {:?}", wait); 
    } else {
        println!("No failures recorded.");
    }

    tracker.record_failure();
    std::thread::sleep(Duration::from_millis(100));
    tracker.record_failure();

    if let Some(wait) = tracker.calculate_wait_time() { 
        println!("After two failures, suggested wait time: {:?}", wait);
    }

    std::thread::sleep(Duration::from_millis(1000));
    tracker.record_failure();
    if let Some(wait) = tracker.calculate_wait_time() { 
        println!("After more failures, suggested wait time: {:?}", wait);
    }
}

use std::collections::HashMap;
use std::fs::File;
use std::io::{self, Write};

struct SensorData {
    timestamp: u64,
    temperature_c: f32,
}

fn process_readings(mut readings: Vec<SensorData>) -> HashMap<u64, f32> {
    let mut result = HashMap::new();
    for data in readings.drain(..) {
        result.insert(data.timestamp, data.temperature_c);
    }
    result
}

fn main() -> io::Result<()> {
    let filename = "sensor_log.txt";
    let mut file = File::create(filename)?;

    let raw_readings = vec![
        SensorData { timestamp: 1678886400, temperature_c: 22.5 },
        SensorData { timestamp: 1678886460, temperature_c: 22.7 },
        SensorData { timestamp: 1678886520, temperature_c: 23.0 },
    ];

    let processed = process_readings(raw_readings);

    for (timestamp, temp) in processed {
        writeln!(file, "Time: {}, Temp: {:.1} C", timestamp, temp)?;
    }

    Ok(())
}

use std::collections::HashMap;

struct VoxelCube {
    x: i32,
    y: i32,
    z: i32,
}

fn process_voxel_map(cubes: Vec<VoxelCube>) -> HashMap<(i32, i32, i32), bool> {
    let mut visible_faces: HashMap<(i32, i32, i32), bool> = HashMap::new();

    for cube in cubes.iter().take(50) {
        let current_key = (cube.x, cube.y, cube.z);

        let neighbors = [ 
            (cube.x + 1, cube.y, cube.z), 
            (cube.x - 1, cube.y, cube.z), 
            (cube.x, cube.y + 1, cube.z),
            (cube.x, cube.y - 1, cube.z),
            (cube.x, cube.y, cube.z + 1),
            (cube.x, cube.y, cube.z - 1),
        ];

        for &(nx, ny, nz) in neighbors.iter() {
            if let Some(neighbor_key) = visible_faces.get(&(nx, ny, nz)) { 
                if !(*neighbor_key) { 
                    visible_faces.insert(current_key, true);
                }
            }
        }
    }

    let (cx, cy, cz) = (0, 0, 0);
    visible_faces.insert((cx, cy, cz), false);
    visible_faces
}

use std::sync::atomic::{AtomicI32, Ordering};
use std::thread;
use std::sync::Arc;

struct GraphState {
    nodes: AtomicI32,
}

impl GraphState {
    fn new() -> Self {
        GraphState { nodes: AtomicI32::new(0) }
    }

    fn process_read(&self, thread_id: i32) -> i32 {
        let current_val = self.nodes.load(Ordering::Relaxed);
        println!("Thread {} read value: {}", thread_id, current_val);
        current_val
    }

    fn process_write(&self, increment: i32, thread_id: i32) -> i32 {
        let initial_value = self.nodes.fetch_add(increment, Ordering::SeqCst);
        println!("Thread {} successfully wrote and saw base value: {}", thread_id, initial_value + 1);
        initial_value + 1
    }
}

fn main() {
    let shared_state = Arc::new(GraphState::new());
    const NUM_THREADS: i32 = 5;
    let mut handles = vec![];

    for i in 0..NUM_THREADS {
        let state_clone = Arc::clone(&shared_state);
        let handle = thread::spawn(move || {
            state_clone.process_read(i);
            thread::sleep(std::time::Duration::from_millis(10));
            state_clone.process_write(1, i);
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }
}
